UPDATE learning_item SET examples = '[{"en":"Phrases are syntactical units.","zh":"短语是句法单位。"},{"en":"To change the units from metric to imperial and vice versa, the ''menu'' button must be clicked.","zh":"要把公制單位換算成英制或反過來操作，鬚點擊“菜單”按鈕。"},{"en":"As soon as we are born, the world gets to work on us and transforms us from merely biological into social units.","zh":"我們一出生在這個世界上，就會開始受到周遭環境的影響，從生物單位慢慢進化成社會單位。"}]' WHERE item_code = 'w_077913';
